PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE IF NOT EXISTS "migrations" ("id" integer primary key autoincrement not null, "migration" varchar not null, "batch" integer not null);
CREATE TABLE IF NOT EXISTS "agencies" ("id" integer primary key autoincrement not null, "name" varchar not null, "slug" varchar not null, "custom_domain" varchar, "logo_path" varchar, "primary_color" varchar not null default '#10B981', "secondary_color" varchar not null default '#18181B', "accent_color" varchar not null default '#F59E0B', "tagline" varchar, "address" text, "phone" varchar, "email" varchar not null, "website" varchar, "timezone" varchar not null default 'UTC', "currency" varchar not null default 'USD', "country_code" varchar not null default 'US', "subscription_plan" varchar not null default 'starter', "subscription_status" varchar not null default 'trialing', "settings" text, "created_at" datetime, "updated_at" datetime, "commission_splits" text, "default_commission_rate" numeric not null default '5', "favicon_path" varchar, "font_family" varchar, "border_radius" varchar not null default 'default', "sidebar_style" varchar not null default 'dark', "custom_css" text, "use_platform_branding" tinyint(1) not null default '0', "ai_credits_balance" integer not null default '200', "ai_credits_allocated_monthly" integer not null default '200', "billing_cycle" varchar not null default 'monthly', "paystack_customer_code" varchar, "paystack_subscription_code" varchar);
CREATE TABLE IF NOT EXISTS "users" ("id" integer primary key autoincrement not null, "agency_id" integer not null, "first_name" varchar not null, "last_name" varchar not null, "email" varchar not null, "phone" varchar, "password" varchar not null, "avatar_path" varchar, "job_title" varchar, "bio" text, "status" varchar not null default 'invited', "email_verified_at" datetime, "two_factor_enabled" tinyint(1) not null default '0', "two_factor_secret" text, "notification_preferences" text, "last_login_at" datetime, "last_active_at" datetime, "remember_token" varchar, "created_at" datetime, "updated_at" datetime, "dashboard_widgets" text, foreign key("agency_id") references "agencies"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "password_reset_tokens" ("email" varchar not null, "token" varchar not null, "created_at" datetime, primary key ("email"));
CREATE TABLE IF NOT EXISTS "sessions" ("id" varchar not null, "user_id" integer, "ip_address" varchar, "user_agent" text, "payload" text not null, "last_activity" integer not null, primary key ("id"));
CREATE TABLE IF NOT EXISTS "cache" ("key" varchar not null, "value" text not null, "expiration" integer not null, primary key ("key"));
CREATE TABLE IF NOT EXISTS "cache_locks" ("key" varchar not null, "owner" varchar not null, "expiration" integer not null, primary key ("key"));
CREATE TABLE IF NOT EXISTS "jobs" ("id" integer primary key autoincrement not null, "queue" varchar not null, "payload" text not null, "attempts" integer not null, "reserved_at" integer, "available_at" integer not null, "created_at" integer not null);
CREATE TABLE IF NOT EXISTS "job_batches" ("id" varchar not null, "name" varchar not null, "total_jobs" integer not null, "pending_jobs" integer not null, "failed_jobs" integer not null, "failed_job_ids" text not null, "options" text, "cancelled_at" integer, "created_at" integer not null, "finished_at" integer, primary key ("id"));
CREATE TABLE IF NOT EXISTS "failed_jobs" ("id" integer primary key autoincrement not null, "uuid" varchar not null, "connection" varchar not null, "queue" varchar not null, "payload" text not null, "exception" text not null, "failed_at" datetime not null default CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS "permissions" ("id" integer primary key autoincrement not null, "name" varchar not null, "guard_name" varchar not null, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "roles" ("id" integer primary key autoincrement not null, "agency_id" integer, "name" varchar not null, "guard_name" varchar not null, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "model_has_permissions" ("permission_id" integer not null, "model_type" varchar not null, "model_id" integer not null, "agency_id" integer not null, foreign key("permission_id") references "permissions"("id") on delete cascade, primary key ("agency_id", "permission_id", "model_id", "model_type"));
CREATE TABLE IF NOT EXISTS "model_has_roles" ("role_id" integer not null, "model_type" varchar not null, "model_id" integer not null, "agency_id" integer not null, foreign key("role_id") references "roles"("id") on delete cascade, primary key ("agency_id", "role_id", "model_id", "model_type"));
CREATE TABLE IF NOT EXISTS "role_has_permissions" ("permission_id" integer not null, "role_id" integer not null, foreign key("permission_id") references "permissions"("id") on delete cascade, foreign key("role_id") references "roles"("id") on delete cascade, primary key ("permission_id", "role_id"));
CREATE TABLE IF NOT EXISTS "team_invitations" ("id" integer primary key autoincrement not null, "agency_id" integer not null, "email" varchar not null, "role" varchar not null, "token" varchar not null, "invited_by" integer not null, "accepted_at" datetime, "created_at" datetime, "updated_at" datetime, foreign key("agency_id") references "agencies"("id") on delete cascade, foreign key("invited_by") references "users"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "notifications" ("id" integer primary key autoincrement not null, "agency_id" integer not null, "user_id" integer not null, "type" varchar not null, "title" varchar not null, "body" text not null, "action_url" varchar, "severity" varchar not null default 'info', "channels_dispatched" text, "read_at" datetime, "created_at" datetime, "updated_at" datetime, foreign key("agency_id") references "agencies"("id") on delete cascade, foreign key("user_id") references "users"("id") on delete cascade);
/****** CORRUPTION ERROR *******/
CREATE TABLE IF NOT EXISTS "ai_usage_logs" ("id" integer primary key autoincrement not null, "agency_id" integer not null, "user_id" integer not null, "feature" varchar not null, "provider" varchar not null, "model" varchar not null, "prompt_tokens" integer not null default '0', "completion_tokens" integer not null default '0', "total_tokens" integer not null default '0', "cost_estimate" numeric not null default '0', "duration_ms" integer not null default '0', "created_at" datetime not null default CURRENT_TIMESTAMP, foreign key("agency_id") references "agencies"("id") on delete cascade, foreign key("user_id") references "users"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "integration_credentials" ("id" integer primary key autoincrement not null, "agency_id" integer not null, "service" varchar not null, "credentials" text not null, "status" varchar not null default 'active', "last_used_at" datetime, "created_at" datetime, "updated_at" datetime, foreign key("agency_id") references "agencies"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "contacts" ("id" integer primary key autoincrement not null, "agency_id" integer not null, "assigned_agent_id" integer, "type" varchar check ("type" in ('buyer', 'seller', 'landlord', 'tenant', 'investor', 'referral_partner')) not null default 'buyer', "first_name" varchar not null, "last_name" varchar not null, "email" varchar, "phone" varchar, "secondary_phone" varchar, "company" varchar, "job_title" varchar, "source" varchar, "source_detail" varchar, "intent_score" integer not null default '0', "status" varchar check ("status" in ('new', 'active', 'qualified', 'nurturing', 'closed', 'archived')) not null default 'new', "preferences" text, "tags" text, "notes" text, "last_contacted_at" datetime, "deleted_at" datetime, "created_at" datetime, "updated_at" datetime, foreign key("agency_id") references "agencies"("id") on delete cascade, foreign key("assigned_agent_id") references "users"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "lead_sources" ("id" integer primary key autoincrement not null, "agency_id" integer not null, "name" varchar not null, "type" varchar check ("type" in ('portal', 'referral', 'walk_in', 'social_media', 'direct', 'campaign', 'other')) not null default 'other', "is_active" tinyint(1) not null default '1', "created_at" datetime, "updated_at" datetime, foreign key("agency_id") references "agencies"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "properties" ("id" integer primary key autoincrement not null, "agency_id" integer not null, "address_line_1" varchar not null, "address_line_2" varchar, "city" varchar not null, "state_province" varchar not null, "country" varchar not null, "postal_code" varchar, "latitude" numeric, "longitude" numeric, "property_type" varchar check ("property_type" in ('house', 'apartment', 'townhouse', 'penthouse', 'land', 'commercial', 'office', 'warehouse')) not null, "property_subtype" varchar, "bedrooms" integer, "bathrooms" integer, "parking_spaces" integer, "floor_area_sqm" numeric, "land_area_sqm" numeric, "year_built" integer, "condition" varchar check ("condition" in ('new', 'excellent', 'good', 'fair', 'needs_work')), "features" text, "description" text, "created_at" datetime, "updated_at" datetime, foreign key("agency_id") references "agencies"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "listings" ("id" integer primary key autoincrement not null, "agency_id" integer not null, "agent_id" integer not null, "property_id" integer not null, "mandate_type" varchar check ("mandate_type" in ('sole', 'open', 'rental')) not null, "status" varchar check ("status" in ('draft', 'active', 'under_offer', 'sold', 'let', 'withdrawn', 'expired')) not null default 'draft', "listing_price" numeric not null, "original_price" numeric, "commission_rate" numeric, "mandate_start_date" date not null, "mandate_end_date" date, "description_short" text, "description_standard" text, "description_long" text, "headline" varchar, "features_highlighted" text, "listing_url" varchar, "days_on_market" integer, "health_score" integer, "portal_ids" text, "seller_report_frequency" varchar check ("seller_report_frequency" in ('weekly', 'biweekly', 'monthly')), "published_at" datetime, "deleted_at" datetime, "created_at" datetime, "updated_at" datetime, "seller_email" varchar, "virtual_tour_url" varchar, "virtual_tour_type" varchar, "is_pocket" tinyint(1) not null default '0', "pocket_token" varchar, "mls_id" varchar, "mls_last_synced_at" datetime, foreign key("agency_id") references "agencies"("id") on delete cascade, foreign key("agent_id") references "users"("id") on delete cascade, foreign key("property_id") references "properties"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "listing_media" ("id" integer primary key autoincrement not null, "listing_id" integer not null, "agency_id" integer not null, "file_type" varchar check ("file_type" in ('image', 'video', 'document', 'floor_plan')) not null default 'image', "file_path" varchar not null, "file_name" varchar not null, "mime_type" varchar, "file_size" integer, "width" integer, "height" integer, "is_cover" tinyint(1) not null default '0', "order" integer not null default '0', "alt_text" varchar, "created_at" datetime, "updated_at" datetime, foreign key("listing_id") references "listings"("id") on delete cascade, foreign key("agency_id") references "agencies"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "portals" ("id" integer primary key autoincrement not null, "name" varchar not null, "code" varchar not null, "is_active" tinyint(1) not null default '1', "base_url" varchar, "logo_path" varchar, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "listing_portal_syncs" ("id" integer primary key autoincrement not null, "listing_id" integer not null, "agency_id" integer not null, "portal_id" integer not null, "status" varchar check ("status" in ('pending', 'syncing', 'synced', 'failed', 'unpublished')) not null default 'pending', "external_id" varchar, "last_synced_at" datetime, "sync_errors" text, "is_active" tinyint(1) not null default '1', "created_at" datetime, "updated_at" datetime, foreign key("listing_id") references "listings"("id") on delete cascade, foreign key("agency_id") references "agencies"("id") on delete cascade, foreign key("portal_id") references "portals"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "chat_sessions" ("id" integer primary key autoincrement not null, "agency_id" integer not null, "user_id" integer not null, "title" varchar, "status" varchar not null default 'active', "created_at" datetime, "updated_at" datetime, foreign key("agency_id") references "agencies"("id") on delete cascade, foreign key("user_id") references "users"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "chat_messages" ("id" integer primary key autoincrement not null, "chat_session_id" integer not null, "role" varchar check ("role" in ('user', 'assistant', 'system')) not null, "content" text, "tool_calls" text, "tool_results" text, "tokens_used" integer, "created_at" datetime, "updated_at" datetime, foreign key("chat_session_id") references "chat_sessions"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "daily_briefs" ("id" integer primary key autoincrement not null, "agency_id" integer not null, "user_id" integer not null, "date" date not null, "priority_actions" text, "deal_alerts" text, "viewing_schedule" text, "market_snapshot" text, "is_read" tinyint(1) not null default '0', "created_at" datetime, "updated_at" datetime, "coaching_tips" text, "goals" text, "ai_summary" text, "focus_score" integer, foreign key("agency_id") references "agencies"("id") on delete cascade, foreign key("user_id") references "users"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "pipeline_stages" ("id" integer primary key autoincrement not null, "agency_id" integer not null, "name" varchar not null, "pipeline_type" varchar check ("pipeline_type" in ('sale', 'rental')) not null default 'sale', "order" integer not null default '0', "is_default" tinyint(1) not null default '0', "is_won" tinyint(1) not null default '0', "is_lost" tinyint(1) not null default '0', "created_at" datetime, "updated_at" datetime, foreign key("agency_id") references "agencies"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "deals" ("id" integer primary key autoincrement not null, "agency_id" integer not null, "pipeline_stage_id" integer not null, "contact_id" integer not null, "listing_id" integer, "assigned_agent_id" integer, "title" varchar not null, "type" varchar check ("type" in ('sale', 'rental')) not null default 'sale', "value" numeric not null default '0', "momentum_score" integer not null default '100', "notes" text, "created_at" datetime, "updated_at" datetime, foreign key("agency_id") references "agencies"("id") on delete cascade, foreign key("pipeline_stage_id") references "pipeline_stages"("id") on delete cascade, foreign key("contact_id") references "contacts"("id") on delete cascade, foreign key("listing_id") references "listings"("id") on delete set null, foreign key("assigned_agent_id") references "users"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "campaigns" ("id" integer primary key autoincrement not null, "agency_id" integer not null, "listing_id" integer not null, "user_id" integer not null, "name" varchar not null, "goal" varchar not null, "status" varchar not null default 'draft', "scheduled_at" datetime, "created_at" datetime, "updated_at" datetime, foreign key("agency_id") references "agencies"("id") on delete cascade, foreign key("listing_id") references "listings"("id") on delete cascade, foreign key("user_id") references "users"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "campaign_contents" ("id" integer primary key autoincrement not null, "campaign_id" integer not null, "channel" varchar not null, "content_body" text not null, "media_paths" text, "status" varchar not null default 'draft', "scheduled_at" datetime, "created_at" datetime, "updated_at" datetime, foreign key("campaign_id") references "campaigns"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "viewings" ("id" integer primary key autoincrement not null, "agency_id" integer not null, "listing_id" integer not null, "contact_id" integer not null, "assigned_agent_id" integer not null, "scheduled_at" datetime not null, "status" varchar not null default 'scheduled', "duration_minutes" integer not null default '30', "notes" text, "created_at" datetime, "updated_at" datetime, "reminder_48h_sent" tinyint(1) not null default '0', "reminder_morning_sent" tinyint(1) not null default '0', "reminder_1h_sent" tinyint(1) not null default '0', "booking_source" varchar, "feedback_survey_sent" tinyint(1) not null default '0', "feedback_token" varchar, "check_in_at" datetime, "outcome_notes" text, "outcome" varchar check ("outcome" in ('interested', 'not_interested', 'offer_expected', 'undecided')), foreign key("agency_id") references "agencies"("id") on delete cascade, foreign key("listing_id") references "listings"("id") on delete cascade, foreign key("contact_id") references "contacts"("id") on delete cascade, foreign key("assigned_agent_id") references "users"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "contact_activities" ("id" integer primary key autoincrement not null, "agency_id" integer not null, "contact_id" integer not null, "user_id" integer, "type" varchar not null default ('note'), "subject" varchar, "body" text, "metadata" text, "occurred_at" datetime not null default (CURRENT_TIMESTAMP), "created_at" datetime, "updated_at" datetime, "deal_id" integer, foreign key("user_id") references users("id") on delete set null on update no action, foreign key("contact_id") references contacts("id") on delete cascade on update no action, foreign key("agency_id") references agencies("id") on delete cascade on update no action, foreign key("deal_id") references "deals"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "stage_checklist_items" ("id" integer primary key autoincrement not null, "agency_id" integer not null, "pipeline_stage_id" integer not null, "deal_id" integer not null, "title" varchar not null, "completed" tinyint(1) not null default '0', "completed_at" datetime, "completed_by" integer, "order" integer not null default '0', "created_at" datetime, "updated_at" datetime, foreign key("agency_id") references "agencies"("id") on delete cascade, foreign key("pipeline_stage_id") references "pipeline_stages"("id") on delete cascade, foreign key("deal_id") references "deals"("id") on delete cascade, foreign key("completed_by") references "users"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "follow_up_sequences" ("id" integer primary key autoincrement not null, "agency_id" integer not null, "contact_id" integer not null, "assigned_agent_id" integer, "name" varchar not null, "status" varchar check ("status" in ('active', 'paused', 'completed', 'cancelled')) not null default 'active', "current_step" integer not null default '0', "next_action_at" datetime, "created_at" datetime, "updated_at" datetime, foreign key("agency_id") references "agencies"("id") on delete cascade, foreign key("contact_id") references "contacts"("id") on delete cascade, foreign key("assigned_agent_id") references "users"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "follow_up_steps" ("id" integer primary key autoincrement not null, "sequence_id" integer not null, "step_number" integer not null, "type" varchar check ("type" in ('email', 'call', 'sms', 'task')) not null default 'email', "subject" varchar, "message_template" text not null, "delay_days" integer not null default '1', "status" varchar check ("status" in ('pending', 'sent', 'skipped')) not null default 'pending', "executed_at" datetime, "created_at" datetime, "updated_at" datetime, foreign key("sequence_id") references "follow_up_sequences"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "viewing_feedbacks" ("id" integer primary key autoincrement not null, "viewing_id" integer not null, "agency_id" integer not null, "overall_rating" integer, "price_perception" integer, "interest_level" varchar, "positive_notes" text, "concerns" text, "would_make_offer" tinyint(1) not null default '0', "agent_notes" text, "created_at" datetime, "updated_at" datetime, foreign key("viewing_id") references "viewings"("id") on delete cascade, foreign key("agency_id") references "agencies"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "transactions" ("id" integer primary key autoincrement not null, "agency_id" integer not null, "deal_id" integer not null, "listing_id" integer, "contact_id" integer, "assigned_agent_id" integer, "attorney_id" integer, "reference" varchar not null, "status" varchar check ("status" in ('initiated', 'fica_pending', 'fica_verified', 'offer_accepted', 'conveyancing', 'registration', 'completed', 'cancelled')) not null default 'initiated', "sale_price" numeric, "commission_rate" numeric not null default '5', "agent_split" numeric not null default '50', "offer_date" date, "deadline" date, "estimated_close_date" date, "closed_at" date, "timeline" text, "notes" text, "created_at" datetime, "updated_at" datetime, foreign key("agency_id") references "agencies"("id") on delete cascade, foreign key("deal_id") references "deals"("id") on delete cascade, foreign key("listing_id") references "listings"("id") on delete set null, foreign key("contact_id") references "contacts"("id") on delete set null, foreign key("assigned_agent_id") references "users"("id") on delete set null, foreign key("attorney_id") references "users"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "commissions" ("id" integer primary key autoincrement not null, "agency_id" integer not null, "transaction_id" integer not null, "deal_id" integer not null, "agent_id" integer, "sale_price" numeric not null, "commission_rate" numeric not null, "gross_commission" numeric not null, "agent_split_percentage" numeric not null, "agent_commission" numeric not null, "agency_commission" numeric not null, "payment_status" varchar check ("payment_status" in ('pending', 'processing', 'paid', 'disputed')) not null default 'pending', "expected_payment_date" date, "paid_at" date, "payment_reference" varchar, "notes" text, "created_at" datetime, "updated_at" datetime, foreign key("agency_id") references "agencies"("id") on delete cascade, foreign key("transaction_id") references "transactions"("id") on delete cascade, foreign key("deal_id") references "deals"("id") on delete cascade, foreign key("agent_id") references "users"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "training_modules" ("id" integer primary key autoincrement not null, "agency_id" integer, "title" varchar not null, "description" text, "category" varchar check ("category" in ('onboarding', 'skills', 'compliance', 'market', 'tools')) not null default 'skills', "type" varchar check ("type" in ('video', 'guide', 'quiz', 'roleplay', 'interactive')) not null default 'guide', "duration" varchar, "thumbnail_color" varchar, "content_url" varchar, "content_body" text, "is_mandatory" tinyint(1) not null default '0', "is_published" tinyint(1) not null default '1', "order" integer not null default '0', "created_at" datetime, "updated_at" datetime, foreign key("agency_id") references "agencies"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "training_progress" ("id" integer primary key autoincrement not null, "user_id" integer not null, "module_id" integer not null, "progress_pct" integer not null default '0', "status" varchar check ("status" in ('not_started', 'in_progress', 'completed')) not null default 'not_started', "started_at" datetime, "completed_at" datetime, "score" integer, "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete cascade, foreign key("module_id") references "training_modules"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "whatsapp_templates" ("id" integer primary key autoincrement not null, "agency_id" integer not null, "name" varchar not null, "category" varchar not null default 'marketing', "body" text not null, "variables" text, "status" varchar check ("status" in ('draft', 'pending_approval', 'approved', 'rejected')) not null default 'draft', "created_at" datetime, "updated_at" datetime, foreign key("agency_id") references "agencies"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "whatsapp_messages" ("id" integer primary key autoincrement not null, "agency_id" integer not null, "contact_id" integer, "template_id" integer, "to_number" varchar not null, "body" text not null, "direction" varchar check ("direction" in ('outbound', 'inbound')) not null default 'outbound', "status" varchar check ("status" in ('queued', 'sent', 'delivered', 'read', 'failed')) not null default 'queued', "external_id" varchar, "sent_at" datetime, "delivered_at" datetime, "created_at" datetime, "updated_at" datetime, "external_message_id" varchar, foreign key("agency_id") references "agencies"("id") on delete cascade, foreign key("contact_id") references "contacts"("id") on delete set null, foreign key("template_id") references "whatsapp_templates"("id") on delete set null);
/****** CORRUPTION ERROR *******/
CREATE TABLE IF NOT EXISTS "meta_ad_campaigns" ("id" integer primary key autoincrement not null, "agency_id" integer not null, "campaign_id" integer, "name" varchar not null, "objective" varchar check ("objective" in ('lead_generation', 'brand_awareness', 'traffic', 'conversions')) not null default 'lead_generation', "budget_daily" numeric, "budget_total" numeric, "start_date" date, "end_date" date, "status" varchar check ("status" in ('draft', 'active', 'paused', 'completed')) not null default 'draft', "external_campaign_id" varchar, "spend" numeric not null default '0', "impressions" integer not null default '0', "clicks" integer not null default '0', "leads" integer not null default '0', "cpm" numeric, "cpc" numeric, "cpl" numeric, "created_at" datetime, "updated_at" datetime, foreign key("agency_id") references "agencies"("id") on delete cascade, foreign key("campaign_id") references "campaigns"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "open_houses" ("id" integer primary key autoincrement not null, "agency_id" integer not null, "listing_id" integer not null, "agent_id" integer not null, "starts_at" datetime not null, "ends_at" datetime not null, "status" varchar not null default 'scheduled', "rsvp_count" integer not null default '0', "attendance_count" integer not null default '0', "notes" text, "rsvp_slug" varchar, "created_at" datetime, "updated_at" datetime, "deleted_at" datetime, foreign key("agency_id") references "agencies"("id") on delete cascade, foreign key("listing_id") references "listings"("id") on delete cascade, foreign key("agent_id") references "users"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "open_house_rsvps" ("id" integer primary key autoincrement not null, "open_house_id" integer not null, "contact_id" integer, "guest_name" varchar not null, "guest_email" varchar, "guest_phone" varchar, "checked_in" tinyint(1) not null default '0', "checked_in_at" datetime, "reminder_sent" tinyint(1) not null default '0', "created_at" datetime, "updated_at" datetime, foreign key("open_house_id") references "open_houses"("id") on delete cascade, foreign key("contact_id") references "contacts"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "listing_graphics" ("id" integer primary key autoincrement not null, "agency_id" integer not null, "listing_id" integer not null, "format" varchar not null, "channel" varchar not null, "file_path" varchar not null, "width" integer not null, "height" integer not null, "file_size" integer, "post_copy" text, "created_at" datetime, "updated_at" datetime, foreign key("agency_id") references "agencies"("id") on delete cascade, foreign key("listing_id") references "listings"("id") on delete cascade);
