CREATE TABLE IF NOT EXISTS "paystack_transactions" ("id" integer primary key autoincrement not null, "agency_id" integer not null, "reference" varchar not null, "type" varchar not null, "event" varchar, "status" varchar not null, "amount" integer not null, "currency" varchar not null default 'NGN', "plan" varchar, "billing_cycle" varchar, "credits_added" integer, "paystack_transaction_id" varchar, "paystack_customer_code" varchar, "paystack_subscription_code" varchar, "authorization_code" varchar, "metadata" text, "created_at" datetime, "updated_at" datetime, foreign key("agency_id") references "agencies"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "personal_access_tokens" ("id" integer primary key autoincrement not null, "tokenable_type" varchar not null, "tokenable_id" integer not null, "name" text not null, "token" varchar not null, "abilities" text, "last_used_at" datetime, "expires_at" datetime, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "agent_numbers" ("id" integer primary key autoincrement not null, "agency_id" integer not null, "user_id" integer not null, "twilio_number" varchar, "twilio_sid" varchar, "active" tinyint(1) not null default ('1'), "created_at" datetime, "updated_at" datetime, "language" varchar not null default ('en'), "display_number" varchar, "number_type" varchar not null default 'twilio_provisioned', "country_code" varchar not null default 'US', "verified" tinyint(1) not null default '0', "verified_at" datetime, "caller_id_sid" varchar, "verification_code" varchar, "verification_expires_at" datetime, foreign key("user_id") references users("id") on delete cascade on update no action, foreign key("agency_id") references agencies("id") on delete cascade on update no action);
CREATE TABLE IF NOT EXISTS "quit_notices" ("id" integer primary key autoincrement not null, "agency_id" integer not null, "lease_id" integer not null, "tenant_id" integer not null, "issued_by" integer not null, "reference" varchar not null, "issue_date" date not null, "vacate_by_date" date not null, "reason" varchar not null, "notice_body" text not null, "ai_draft" text, "status" varchar check ("status" in ('drafted', 'sent', 'acknowledged', 'disputed', 'withdrawn', 'completed')) not null default 'drafted', "delivery_method" varchar not null default 'email', "sent_at" datetime, "acknowledged_at" datetime, "tenant_response" text, "internal_notes" text, "deleted_at" datetime, "created_at" datetime, "updated_at" datetime, foreign key("agency_id") references "agencies"("id") on delete cascade, foreign key("lease_id") references "leases"("id") on delete cascade, foreign key("tenant_id") references "tenants"("id") on delete cascade, foreign key("issued_by") references "users"("id"));
